import React, { useState } from "react";
import logo from "./logo.png";

function App() {
  const [currentPage, setCurrentPage] = useState("home");

  // Function to handle navigation
  const navigateTo = (page) => {
    setCurrentPage(page);
  };

  // Home page content
  const Home = () => (
    <div style={styles.homeContainer}>
      <div style={styles.logoSection}>
        <img src={logo} alt="Logo" style={styles.logo} />
      </div>
      <div style={styles.descriptionSection}>
        <h1>Welcome to MusicStreamingApp</h1>
        <p>
          Discover your favorite music, create playlists, and share your
          experience with friends. Our app is designed to give you an
          exceptional music streaming experience with an intuitive interface
          and seamless playback.
        </p>
      </div>
    </div>
  );

  // Login page content (from our previous work)
  const Login = () => {
    const [activeForm, setActiveForm] = useState("login");
    const [formData, setFormData] = useState({
      email: "",
      password: "",
      confirmPassword: "",
    });

    const handleFormSwitch = (form) => {
      setActiveForm(form);
      setFormData({ email: "", password: "", confirmPassword: "" });
    };

    const handleSubmit = (event) => {
      event.preventDefault();
      if (
        activeForm === "signup" &&
        formData.password !== formData.confirmPassword
      ) {
        alert("Passwords do not match");
        return;
      }
      alert(
        `${activeForm === "login" ? "Logged In" : "Account Created"} Successfully!`
      );
    };

    const handleInputChange = (e) => {
      const { name, value } = e.target;
      setFormData((prev) => ({ ...prev, [name]: value }));
    };

    return (
      <div style={styles.container}>
        <h1>{activeForm === "login" ? "Login" : "Create Account"}</h1>
        <form onSubmit={handleSubmit} style={styles.form}>
          <input
            type="email"
            name="email"
            placeholder="Email"
            value={formData.email}
            onChange={handleInputChange}
            style={styles.input}
            required
          />
          <input
            type="password"
            name="password"
            placeholder="Password"
            value={formData.password}
            onChange={handleInputChange}
            style={styles.input}
            required
          />
          {activeForm === "signup" && (
            <input
              type="password"
              name="confirmPassword"
              placeholder="Confirm Password"
              value={formData.confirmPassword}
              onChange={handleInputChange}
              style={styles.input}
              required
            />
          )}
          <button type="submit" style={styles.button}>
            {activeForm === "login" ? "Login" : "Sign Up"}
          </button>
        </form>
        <p style={styles.toggleText}>
          {activeForm === "login"
            ? "Don't have an account?"
            : "Already have an account?"}{" "}
          &nbsp;
          <button
            type="button"
            onClick={() =>
              handleFormSwitch(activeForm === "login" ? "signup" : "login")
            }
            style={styles.toggleButton}
          >
            {activeForm === "login" ? "Create Account" : "Login"}
          </button>
        </p>
      </div>
    );
  };

  return (
    <div>
      <nav style={styles.navbar}>
        <button style={styles.navButton} onClick={() => navigateTo("home")}>
          Home
        </button>
        <button style={styles.navButton} onClick={() => navigateTo("about")}>
          About
        </button>
        <button style={styles.navButton} onClick={() => navigateTo("contact")}>
          Contact
        </button>
        <button style={styles.navButton} onClick={() => navigateTo("login")}>
          Login
        </button>
      </nav>
      {currentPage === "home" && <Home />}
      {currentPage === "login" && <Login />}
    </div>
  );
}

const styles = {
  navbar: {
    display: "flex",
    justifyContent: "space-around",
    backgroundColor: "#007BFF",
    padding: "10px",
  },
  navButton: {
    color: "white",
    backgroundColor: "transparent",
    border: "none",
    fontSize: "18px",
    cursor: "pointer",
  },
  homeContainer: {
    display: "flex",
    height: "100vh",
    backgroundColor: "azure",
  },
  logoSection: {
    flex: 1,
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    backgroundColor: "white",
  },
  logo: {
    width: "150px",
  },
  descriptionSection: {
    flex: 1,
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    flexDirection: "column",
    color: "black",
    padding: "20px",
    textAlign: "center",
  },
  container: {
    fontFamily: "Arial, sans-serif",
    maxWidth: "400px",
    margin: "0 auto",
    textAlign: "center",
    padding: "20px",
    border: "1px solid #ccc",
    borderRadius: "8px",
    boxShadow: "0 2px 5px rgba(0,0,0,0.1)",
  },
  form: {
    display: "flex",
    flexDirection: "column",
    gap: "10px",
  },
  input: {
    padding: "10px",
    fontSize: "16px",
    borderRadius: "4px",
    border: "1px solid #ccc",
  },
  button: {
    padding: "10px",
    fontSize: "16px",
    backgroundColor: "#007BFF",
    color: "white",
    border: "none",
    borderRadius: "4px",
    cursor: "pointer",
  },
  toggleText: {
    marginTop: "10px",
  },
  toggleButton: {
    fontSize: "16px",
    color: "#007BFF",
    background: "none",
    border: "none",
    cursor: "pointer",
  },
};

export default App;
